const bookingRows = $input.all();

// Get client config from the Execute Workflow Trigger node
const client = $('🚀 Nhận cấu hình khách').first().json;

const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const week1Start = new Date(today); week1Start.setDate(today.getDate() - 7);
const week2Start = new Date(today); week2Start.setDate(today.getDate() - 14);
const month1Start = new Date(today); month1Start.setDate(today.getDate() - 30);

let thisWeek = { bookings: 0, revenue: 0, services: {}, newCustomers: new Set(), phones: new Set() };
let lastWeek = { bookings: 0, revenue: 0, phones: new Set() };
let thisMonth = { bookings: 0, revenue: 0, services: {}, phones: new Set() };
const allPhones = new Set();

for (const item of bookingRows) {
  const row = item.json;
  const phone = row.phone || row.Phone || row.sdt || '';
  if (!phone) continue;

  const dateStr = row.checkout || row.checkin || row.created_at || '';
  if (!dateStr) continue;

  let visitDate;
  if (dateStr.includes('/')) {
    const parts = dateStr.split('/');
    visitDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
  } else {
    visitDate = new Date(dateStr);
  }
  if (isNaN(visitDate.getTime())) continue;

  const revenue = parseFloat(row.revenue || row.amount || row.price || row.gia_tien || row.total || row.tong_tien || 0);
  const service = row.service || row.dich_vu || 'Khac';

  if (visitDate < week1Start) allPhones.add(phone);

  if (visitDate >= week1Start && visitDate < today) {
    thisWeek.bookings++;
    thisWeek.revenue += revenue;
    thisWeek.phones.add(phone);
    thisWeek.services[service] = (thisWeek.services[service] || 0) + 1;
    if (!allPhones.has(phone)) thisWeek.newCustomers.add(phone);
  }
  if (visitDate >= week2Start && visitDate < week1Start) {
    lastWeek.bookings++;
    lastWeek.revenue += revenue;
    lastWeek.phones.add(phone);
  }
  if (visitDate >= month1Start && visitDate < today) {
    thisMonth.bookings++;
    thisMonth.revenue += revenue;
    thisMonth.phones.add(phone);
    thisMonth.services[service] = (thisMonth.services[service] || 0) + 1;
  }
}

const topServices = (obj) => Object.entries(obj)
  .sort((a, b) => b[1] - a[1]).slice(0, 3)
  .map(([s, c]) => s + ': ' + c + ' luot').join(', ') || 'Chua co du lieu';

const bookingChange = lastWeek.bookings > 0
  ? Math.round((thisWeek.bookings - lastWeek.bookings) / lastWeek.bookings * 100) : 0;
const revenueChange = lastWeek.revenue > 0
  ? Math.round((thisWeek.revenue - lastWeek.revenue) / lastWeek.revenue * 100) : 0;

const trendB = bookingChange > 0 ? 'tang +' + bookingChange + '%' : bookingChange < 0 ? 'giam ' + bookingChange + '%' : 'khong doi';
const trendR = revenueChange > 0 ? 'tang +' + revenueChange + '%' : revenueChange < 0 ? 'giam ' + revenueChange + '%' : 'khong doi';

const fmt = (n) => n > 0 ? n.toLocaleString('vi-VN') + ' d' : 'Chua nhap';

const weekLabel = week1Start.toLocaleDateString('vi-VN') + ' - ' + new Date(today.getTime() - 86400000).toLocaleDateString('vi-VN');
const monthLabel = month1Start.toLocaleDateString('vi-VN') + ' - ' + new Date(today.getTime() - 86400000).toLocaleDateString('vi-VN');

const summary = [
  'TUAN NAY (' + weekLabel + ')',
  '- Tong booking: ' + thisWeek.bookings,
  '- Doanh thu: ' + fmt(thisWeek.revenue),
  '- Khach moi: ' + thisWeek.newCustomers.size,
  '- Top dich vu: ' + topServices(thisWeek.services),
  '',
  'TUAN TRUOC (so sanh)',
  '- Booking: ' + lastWeek.bookings + ' (' + trendB + ')',
  '- Doanh thu: ' + fmt(lastWeek.revenue) + ' (' + trendR + ')',
  '',
  'THANG NAY (' + monthLabel + ')',
  '- Tong booking: ' + thisMonth.bookings,
  '- Doanh thu: ' + fmt(thisMonth.revenue),
  '- Khach doc lap: ' + thisMonth.phones.size,
  '- Top dich vu: ' + topServices(thisMonth.services)
].join('\n');

const aiBody = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [
    {
      role: 'system',
      content: 'Ban la chuyen gia phan tich kinh doanh cho ' + client.name + '. Dua tren so lieu, viet bao cao ngan bang tieng Viet (toi da 120 tu): (1) Nhan xet hieu suat tuan nay, (2) Xu huong noi bat, (3) 2 khuyen nghi cu the. Khong dung Markdown.'
    },
    { role: 'user', content: 'So lieu:\n' + summary }
  ],
  max_tokens: 250,
  temperature: 0.6
});

return [{
  json: {
    client_id: client.client_id,
    client_name: client.name,
    telegram_chat_id: client.telegram_chat_id,
    week_label: weekLabel,
    month_label: monthLabel,
    week_bookings: thisWeek.bookings,
    week_revenue: thisWeek.revenue,
    week_new_customers: thisWeek.newCustomers.size,
    month_bookings: thisMonth.bookings,
    month_revenue: thisMonth.revenue,
    trend_booking: trendB,
    trend_revenue: trendR,
    top_services_week: topServices(thisWeek.services),
    top_services_month: topServices(thisMonth.services),
    fmt_week_revenue: fmt(thisWeek.revenue),
    fmt_month_revenue: fmt(thisMonth.revenue),
    ai_body: aiBody
  }
}];
